import React, { useEffect, useMemo, useRef, useState } from 'react';
import { useSearchParams } from 'react-router-dom';
import { useCart } from '../../context/CartContext';
import categoryService from '../../services/categoryService';
import productService from '../../services/productService';

const DASHBOARD_PRODUCTS_CACHE_KEY = 'dashboard_products_cache_v1';

const CAR_BRANDS = [
    // Japanese Brands
    'Toyota',
    'Honda',
    'Nissan',
    'Mazda',
    'Subaru',
    'Mitsubishi',
    'Suzuki',
    'Lexus',
    'Acura',
    'Infiniti',
    // German Brands
    'BMW',
    'Mercedes-Benz',
    'Audi',
    'Volkswagen',
    'Porsche',
    'Opel',
    // American Brands
    'Ford',
    'Chevrolet',
    'Tesla',
    'Jeep',
    'Dodge',
    'GMC',
    'Cadillac',
    'Chrysler',
    // Korean Brands
    'Hyundai',
    'Kia',
    'Genesis',
    // British Brands
    'Rolls-Royce',
    'Bentley',
    'Jaguar',
    'Land Rover',
    'Mini',
    'Aston Martin',
    // Italian Brands
    'Ferrari',
    'Lamborghini',
    'Maserati',
    'Alfa Romeo',
    'Fiat',
    // French Brands
    'Peugeot',
    'Renault',
    'Citroën',
    'Bugatti',
    // Chinese Brands
    'BYD',
    'Geely',
    'NIO',
    'Chery',
    'Great Wall Motors',
    'XPeng',
    // Other Brands
    'Volvo',
    'Škoda',
    'SEAT',
    'Saab',
    'Tata Motors',
    'Mahindra',
];

const VEHICLE_TYPE_PRESETS = [
    'Toyota',
    'Honda',
    'Nissan',
    'Mazda',
    'Subaru',
    'Mitsubishi',
    'Suzuki',
    'Lexus (Toyota luxury)',
    'Acura (Honda luxury)',
    'Infiniti (Nissan luxury)',
    'BMW',
    'Mercedes-Benz',
    'Audi',
    'Volkswagen (VW)',
    'Porsche',
    'Opel',
    'Ford',
    'Chevrolet',
    'Tesla',
    'Jeep',
    'Dodge',
    'GMC',
    'Cadillac',
    'Chrysler',
    'Hyundai',
    'Kia',
    'Genesis',
    'Rolls-Royce',
    'Bentley',
    'Jaguar',
    'Land Rover',
    'Mini',
    'Aston Martin',
    'Ferrari',
    'Lamborghini',
    'Maserati',
    'Alfa Romeo',
    'Fiat',
    'Peugeot',
    'Renault',
    'Citroën',
    'Bugatti',
    'BYD',
    'Geely',
    'NIO',
    'Chery',
    'Great Wall Motors (GWM)',
    'XPeng',
    'Volvo',
    'Škoda',
    'SEAT',
    'Saab',
    'Tata Motors',
    'Mahindra',
];

export default function DashboardProducts() {
    const { addItem } = useCart();
    const [searchParams, setSearchParams] = useSearchParams();
    const [products, setProducts] = useState(() => {
        try {
            const raw = localStorage.getItem(DASHBOARD_PRODUCTS_CACHE_KEY);
            const parsed = raw ? JSON.parse(raw) : null;
            return Array.isArray(parsed?.products) ? parsed.products : [];
        } catch {
            return [];
        }
    });
    const [categories, setCategories] = useState(() => {
        try {
            const raw = localStorage.getItem(DASHBOARD_PRODUCTS_CACHE_KEY);
            const parsed = raw ? JSON.parse(raw) : null;
            return Array.isArray(parsed?.categories) ? parsed.categories : [];
        } catch {
            return [];
        }
    });
    const [loading, setLoading] = useState(() => products.length === 0);
    const [isRefreshing, setIsRefreshing] = useState(false);
    const [query, setQuery] = useState(searchParams.get('search') || '');
    const [brandFilter, setBrandFilter] = useState(searchParams.get('brand') || 'all');
    const [brandSearchOpen, setBrandSearchOpen] = useState(false);
    const [brandSearch, setBrandSearch] = useState('');
    const [vehicleTypeFilter, setVehicleTypeFilter] = useState(searchParams.get('vehicle_type') || 'all');
    const [vehicleTypeSearchOpen, setVehicleTypeSearchOpen] = useState(false);
    const [vehicleTypeSearch, setVehicleTypeSearch] = useState('');
    const [notice, setNotice] = useState('');
    const [addingProductId, setAddingProductId] = useState(null);
    const [recentlyAddedProductId, setRecentlyAddedProductId] = useState(null);
    const recentlyAddedTimerRef = useRef<number | null>(null);

    useEffect(() => {
        setQuery(searchParams.get('search') || '');
        setBrandFilter(searchParams.get('brand') || 'all');
        setVehicleTypeFilter(searchParams.get('vehicle_type') || 'all');
    }, [searchParams]);

    // Close brand/vehicle type dropdowns when clicking outside or pressing Escape
    useEffect(() => {
        const handleClickOutside = (e) => {
            if (brandSearchOpen && !e.target.closest('.brand-search-container')) {
                setBrandSearchOpen(false);
            }
            if (vehicleTypeSearchOpen && !e.target.closest('.vehicle-type-search-container')) {
                setVehicleTypeSearchOpen(false);
            }
        };

        const handleEscape = (e) => {
            if (e.key === 'Escape') {
                setBrandSearchOpen(false);
                setVehicleTypeSearchOpen(false);
            }
        };

        document.addEventListener('click', handleClickOutside);
        document.addEventListener('keydown', handleEscape);
        return () => {
            document.removeEventListener('click', handleClickOutside);
            document.removeEventListener('keydown', handleEscape);
        };
    }, [brandSearchOpen, vehicleTypeSearchOpen]);

    const extractCollection = (response) => {
        const payload = response?.data?.data;

        if (Array.isArray(payload)) {
            return payload;
        }

        if (Array.isArray(payload?.data)) {
            return payload.data;
        }

        if (Array.isArray(response?.data?.data?.data)) {
            return response.data.data.data;
        }

        return [];
    };

    const selectedCategory = searchParams.get('category') || 'all';

    const brands = useMemo(() => {
        const set = new Set<string>();
        CAR_BRANDS.forEach((brand) => set.add(brand));
        products.forEach((product) => {
            if (product.brand) {
                set.add(product.brand.trim());
            }
        });

        return Array.from(set).sort((a, b) => a.localeCompare(b));
    }, [products]);

    const vehicleTypes = useMemo(() => {
        const set = new Set<string>();
        VEHICLE_TYPE_PRESETS.forEach((item) => set.add(item));

        products.forEach((product) => {
            const value = (product.vehicle_compatibility || '').trim();
            if (value) {
                set.add(value);
            }

            const brandValue = (product.brand || '').trim();
            if (brandValue) {
                set.add(brandValue);
            }
        });

        return Array.from(set).sort((a, b) => a.localeCompare(b));
    }, [products]);

    const maxProductPrice = useMemo(() => {
        const values = products.map((product) => Number(product.price || 0));
        const peak = values.length ? Math.max(...values) : 500;
        return Math.max(500, Math.ceil(peak / 100) * 100);
    }, [products]);

    const [maxPriceFilter, setMaxPriceFilter] = useState(500);

    useEffect(() => {
        let active = true;

        const loadData = async () => {
            try {
                if (products.length === 0) {
                    setLoading(true);
                } else {
                    setIsRefreshing(true);
                }

                const [productsRes, categoriesRes] = await Promise.all([
                    productService.getAll({ per_page: 1000, sort_by: 'created_at', sort_order: 'desc' }),
                    categoryService.getAll(),
                ]);

                if (!active) {
                    return;
                }

                const nextProducts = extractCollection(productsRes);
                const nextCategories = extractCollection(categoriesRes);

                setProducts(nextProducts);
                setCategories(nextCategories);
                localStorage.setItem(
                    DASHBOARD_PRODUCTS_CACHE_KEY,
                    JSON.stringify({ products: nextProducts, categories: nextCategories })
                );
            } catch {
                if (active) {
                    if (products.length === 0) {
                        setProducts([]);
                        setCategories([]);
                    }
                }
            } finally {
                if (active) {
                    setLoading(false);
                    setIsRefreshing(false);
                }
            }
        };

        loadData();

        return () => {
            active = false;
        };
    }, []);

    useEffect(() => {
        if (!notice) {
            return undefined;
        }

        const t = setTimeout(() => setNotice(''), 2000);
        return () => clearTimeout(t);
    }, [notice]);

    useEffect(() => {
        setMaxPriceFilter(maxProductPrice);
    }, [maxProductPrice]);

    const filteredProducts = useMemo(() => {
        const q = query.trim().toLowerCase();
        const normalizedBrand = brandFilter.trim().toLowerCase();
        const normalizedVehicleType = vehicleTypeFilter.trim().toLowerCase();

        return products.filter((product) => {
            const matchesCategory = selectedCategory === 'all' || String(product.category_id) === String(selectedCategory);
            const productBrand = String(product.brand || '').trim().toLowerCase();
            const matchesBrand = normalizedBrand === 'all' || productBrand === normalizedBrand;
            const compatibilityValue = String(product.vehicle_compatibility || '').trim().toLowerCase();
            const matchesVehicleType = normalizedVehicleType === 'all'
                || compatibilityValue === normalizedVehicleType
                || productBrand === normalizedVehicleType;
            const haystack = [product.name, product.brand, product.slug].filter(Boolean).join(' ').toLowerCase();
            const matchesText = !q || haystack.includes(q);
            const matchesPrice = Number(product.price || 0) <= Number(maxPriceFilter || 0);

            return matchesCategory && matchesBrand && matchesVehicleType && matchesText && matchesPrice;
        });
    }, [products, query, selectedCategory, brandFilter, vehicleTypeFilter, maxPriceFilter]);

    const onCategoryChange = (value) => {
        const next = new URLSearchParams(searchParams);

        if (value === 'all') {
            next.delete('category');
            setSearchParams(next);
            return;
        }

        next.set('category', value);
        setSearchParams(next);
    };

    const syncParam = (key, value) => {
        const next = new URLSearchParams(searchParams);
        if (!value || value === 'all') {
            next.delete(key);
        } else {
            next.set(key, value);
        }

        setSearchParams(next);
    };

    const resetFilters = () => {
        setQuery('');
        setBrandFilter('all');
        setVehicleTypeFilter('all');
        setMaxPriceFilter(maxProductPrice);
        setSearchParams(new URLSearchParams());
    };

    const getProductImage = (product) => {
        if (Array.isArray(product.images) && product.images.length > 0) {
            return product.images[0];
        }

        if (typeof product.images === 'string') {
            try {
                const parsed = JSON.parse(product.images);
                if (Array.isArray(parsed) && parsed.length > 0) {
                    return parsed[0];
                }
            } catch {
                return '/images/carvex.png';
            }
        }

        return '/images/carvex.png';
    };

    const formatPeso = (value) => {
        const amount = Number(value || 0);
        return new Intl.NumberFormat('en-PH', {
            style: 'currency',
            currency: 'PHP',
            minimumFractionDigits: 2,
            maximumFractionDigits: 2,
        }).format(amount);
    };

    const totalProducts = products.length;
    const totalBrands = brands.length;
    const totalVehicleTypes = VEHICLE_TYPE_PRESETS.length;

    const formatStock = (stock) => {
        const quantity = Number(stock || 0);

        if (quantity <= 0) {
            return 'Out of stock';
        }

        if (quantity < 5) {
            return `${quantity} left`;
        }

        return 'In stock';
    };

    const handleAdd = (product) => {
        if (addingProductId === product.id) {
            return;
        }

        setAddingProductId(product.id);

        window.setTimeout(() => {
            setAddingProductId((current) => (current === product.id ? null : current));
        }, 320);

        addItem(product.id, 1, {
                id: product.id,
                name: product.name,
                brand: product.brand,
                price: Number(product.price || 0),
                images: product.images,
            })
            .then(() => {
            setNotice(`${product.name} added to cart.`);
                setRecentlyAddedProductId(product.id);

                if (recentlyAddedTimerRef.current !== null) {
                    window.clearTimeout(recentlyAddedTimerRef.current);
                }

                recentlyAddedTimerRef.current = window.setTimeout(() => {
                    setRecentlyAddedProductId((current) => (current === product.id ? null : current));
                    recentlyAddedTimerRef.current = null;
                }, 900);
            })
            .catch((error) => {
            const message = error?.response?.data?.message || 'Unable to add to cart right now.';
            setNotice(message);
                setRecentlyAddedProductId((current) => (current === product.id ? null : current));
            });
    };

    useEffect(() => () => {
        if (recentlyAddedTimerRef.current !== null) {
            window.clearTimeout(recentlyAddedTimerRef.current);
        }
    }, []);

    return (
        <section className="customer-products-page">
            <header className="customer-products-header">
                <div className="customer-products-header__copy">
                    <h2>Browse Car Parts</h2>
                    <p>Find the right parts, compare the best prices, and add to cart in seconds.</p>
                </div>

            </header>

            <div className="customer-products-search">
                <span className="customer-products-search__icon" aria-hidden="true">Search</span>
                <input
                    type="text"
                    value={query}
                    onChange={(e) => {
                        const value = e.target.value;
                        setQuery(value);
                        syncParam('search', value.trim());
                    }}
                    placeholder="Search by name, brand, or description..."
                />
            </div>

            {notice && <div className="dashboard-notice">{notice}</div>}

            <div className="customer-products-layout">
                <aside className="customer-products-filters">
                    <div className="customer-filter-group">
                        <label>Category</label>
                        <select value={selectedCategory} onChange={(e) => onCategoryChange(e.target.value)}>
                            <option value="all">All Categories</option>
                            {categories.map((category) => (
                                <option key={category.id} value={String(category.id)}>{category.name}</option>
                            ))}
                        </select>
                    </div>

                    <div className="customer-filter-group">
                        <label>Brand</label>
                        <div className="brand-search-container">
                            <input
                                type="text"
                                placeholder={brandFilter === 'all' ? 'All Brands' : brandFilter}
                                value={brandSearch}
                                onChange={(e) => setBrandSearch(e.target.value)}
                                onFocus={() => setBrandSearchOpen(true)}
                                className="brand-search-input"
                            />
                            {brandSearchOpen && (
                                <div className="brand-search-dropdown">
                                    <div
                                        key="all"
                                        className={`brand-search-option ${brandFilter === 'all' ? 'active' : ''}`}
                                        onClick={() => {
                                            setBrandFilter('all');
                                            setBrandSearch('');
                                            setBrandSearchOpen(false);
                                            syncParam('brand', 'all');
                                        }}
                                    >
                                        All Brands
                                    </div>
                                    {brands
                                        .filter((b) => b.toLowerCase().includes(brandSearch.toLowerCase()))
                                        .map((brand) => (
                                            <div
                                                key={brand}
                                                className={`brand-search-option ${brandFilter === brand ? 'active' : ''}`}
                                                onClick={() => {
                                                    setBrandFilter(brand);
                                                    setBrandSearch('');
                                                    setBrandSearchOpen(false);
                                                    syncParam('brand', brand);
                                                }}
                                            >
                                                {brand}
                                            </div>
                                        ))}
                                </div>
                            )}
                        </div>
                    </div>

                    <div className="customer-filter-group">
                        <label>Vehicle Type</label>
                        <div className="vehicle-type-search-container">
                            <input
                                type="text"
                                placeholder={vehicleTypeFilter === 'all' ? 'All Types' : vehicleTypeFilter}
                                value={vehicleTypeSearch}
                                onChange={(e) => setVehicleTypeSearch(e.target.value)}
                                onFocus={() => setVehicleTypeSearchOpen(true)}
                                className="vehicle-type-search-input"
                            />
                            {vehicleTypeSearchOpen && (
                                <div className="vehicle-type-search-dropdown">
                                    <div
                                        key="all"
                                        className={`vehicle-type-search-option ${vehicleTypeFilter === 'all' ? 'active' : ''}`}
                                        onClick={() => {
                                            setVehicleTypeFilter('all');
                                            setVehicleTypeSearch('');
                                            setVehicleTypeSearchOpen(false);
                                            syncParam('vehicle_type', 'all');
                                        }}
                                    >
                                        All Types
                                    </div>
                                    {vehicleTypes
                                        .filter((v) => v.toLowerCase().includes(vehicleTypeSearch.toLowerCase()))
                                        .map((vehicleType) => (
                                            <div
                                                key={vehicleType}
                                                className={`vehicle-type-search-option ${vehicleTypeFilter === vehicleType ? 'active' : ''}`}
                                                onClick={() => {
                                                    setVehicleTypeFilter(vehicleType);
                                                    setVehicleTypeSearch('');
                                                    setVehicleTypeSearchOpen(false);
                                                    syncParam('vehicle_type', vehicleType);
                                                }}
                                            >
                                                {vehicleType}
                                            </div>
                                        ))}
                                </div>
                            )}
                        </div>
                    </div>

                    <div className="customer-filter-group">
                        <label>Price Range: {formatPeso(0)} - {formatPeso(maxPriceFilter)}</label>
                        <input
                            type="range"
                            min="0"
                            max={maxProductPrice}
                            value={maxPriceFilter}
                            onChange={(e) => setMaxPriceFilter(Number(e.target.value))}
                        />
                    </div>

                    <button type="button" className="btn btn-outline-primary" onClick={resetFilters}>
                        Clear Filters
                    </button>
                </aside>

                <div className="customer-products-results">
                    <p className="customer-products-count">{filteredProducts.length} products found</p>

                    {loading ? (
                        <div className="customer-products-empty">Products are on the way.</div>
                    ) : filteredProducts.length === 0 ? (
                        <div className="customer-products-empty">No products found. Try changing your filters.</div>
                    ) : (
                        <div className="customer-products-grid">
                            {filteredProducts.map((product) => (
                                <article key={product.id} className="customer-product-card">
                                    <div className="customer-product-card__image">
                                                <div className="customer-product-card__badge">
                                                    {product.brand || 'CarVex'}
                                                </div>
                                        <img src={getProductImage(product)} alt={product.name} />
                                    </div>
                                    <div className="customer-product-card__body">
                                        <div className="customer-product-card__meta">
                                            <h3>{product.name}</h3>
                                            <p>{product.brand || 'CarVex'}</p>
                                        </div>
                                        <div className="customer-product-card__footer">
                                                    <div className="customer-product-card__price-block">
                                                        <strong>{formatPeso(product.price)}</strong>
                                                        <span>{formatStock(product.stock)}</span>
                                                    </div>
                                                    {Number(product.stock || 0) > 0 ? (
                                                        <button
                                                            type="button"
                                                            className="btn btn-primary btn-sm"
                                                            onClick={() => handleAdd(product)}
                                                            disabled={addingProductId === product.id}
                                                        >
                                                            {addingProductId === product.id ? 'Adding...' : 'Add to Cart'}
                                                        </button>
                                                    ) : (
                                                        <button type="button" className="btn btn-disabled btn-sm" disabled>
                                                            Out of Stock
                                                        </button>
                                                    )}
                                        </div>
                                    </div>
                                </article>
                            ))}
                        </div>
                    )}
                </div>
            </div>
        </section>
    );
}
