import api from './api';
import axios, { AxiosRequestConfig } from 'axios';

const SUPABASE_URL = String(process.env.MIX_SUPABASE_URL || '').trim();
const SUPABASE_ANON_KEY = String(process.env.MIX_SUPABASE_ANON_KEY || '').trim();
const CAN_USE_SUPABASE = SUPABASE_URL !== '' && SUPABASE_ANON_KEY !== '';

const supabaseRest = axios.create({
    baseURL: `${SUPABASE_URL.replace(/\/+$/, '')}/rest/v1`,
    headers: {
        apikey: SUPABASE_ANON_KEY,
        Authorization: `Bearer ${SUPABASE_ANON_KEY}`,
        'Content-Type': 'application/json',
    },
    timeout: 12000,
});

const shouldFallback = (error: any): boolean => {
    const status = error?.response?.status;
    return status >= 500 || status === 0 || !status;
};

export const categoryService = {
    getAll: async (config?: AxiosRequestConfig) => {
        try {
            return await api.get('/categories', config);
        } catch (error) {
            if (!CAN_USE_SUPABASE || !shouldFallback(error)) {
                throw error;
            }

            const res = await supabaseRest.get('/categories?select=*&order=name.asc');
            return {
                data: {
                    message: 'Categories retrieved successfully',
                    data: Array.isArray(res.data) ? res.data : [],
                },
            };
        }
    },
    
    getById: async (id: string | number, config?: AxiosRequestConfig) => {
        try {
            return await api.get(`/categories/${id}`, config);
        } catch (error) {
            if (!CAN_USE_SUPABASE || !shouldFallback(error)) {
                throw error;
            }

            const query = /^\d+$/.test(String(id))
                ? `/categories?select=*&id=eq.${id}&limit=1`
                : `/categories?select=*&slug=eq.${id}&limit=1`;
            const res = await supabaseRest.get(query);
            const item = Array.isArray(res.data) ? (res.data[0] || null) : null;

            return {
                data: {
                    message: item ? 'Category retrieved successfully' : 'Category not found',
                    data: item,
                },
            };
        }
    },
};

export default categoryService;
